import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); Q = int(next(it))
        a = [0] + [int(next(it)) for _ in range(N)]
        for __ in range(Q):
            typ = int(next(it))
            if typ == 1:
                i = int(next(it)); x = int(next(it))
                a[i] = x
            else:
                L = int(next(it)); R = int(next(it))
                best = float('inf'); bestX = L; bestY = L
                for x in range(L, R+1):
                    s = 0
                    for y in range(x, R+1):
                        s += a[y]
                        val = abs(math.sin(s * math.pi / 180.0))
                        if val < best - 1e-12:
                            best = val; bestX = x; bestY = y
                out_lines.append(f"{bestX} {bestY}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

